    92→/**
    93→ * Seed built-in capabilities on activation.
    94→ */
    95→function agentpress_seed_capabilities() {
    96→    $capabilities = array(
    97→        array(
    98→            'slug' => 'content_writer',
    99→            'title' => 'Content Writer',
   100→            'description' => 'Generates written content using Claude API.',
   101→        ),
   102→        array(
   103→            'slug' => 'image_generator',
   104→            'title' => 'Image Generator',
   105→            'description' => 'Generates images using Cloudflare Workers AI.',
   106→        ),
   107→    );
   108→
   109→    foreach ($capabilities as $cap) {
   110→        // Check if capability already exists
   111→        $existing = get_posts(array(
   112→            'post_type' => 'agentpress_capability',
   113→            'name' => $cap['slug'],
   114→            'posts_per_page' => 1,
   115→            'post_status' => 'any',
   116→        ));
