   120→                'post_type' => 'agentpress_capability',
   121→                'post_title' => $cap['title'],
   122→                'post_name' => $cap['slug'],
   123→                'post_status' => 'publish',
   124→                'meta_input' => array(
   125→                    '_capability_slug' => $cap['slug'],
   126→                    '_capability_description' => $cap['description'],
   127→                ),
   128→            ));
   129→        }
   130→    }
   131→}
