   133→/**
   134→ * Create default settings option.
   135→ */
   136→function agentpress_create_default_settings() {
   137→    $default_settings = array(
   138→        'default_model' => 'claude-3-5-sonnet-20241022',
   139→        'claude_api_key' => '',
   140→        'cf_worker_url' => '',
