   166→/**
   167→ * Plugin deactivation hook.
   168→ */
   169→function agentpress_deactivate() {
   170→    // Flush rewrite rules on deactivation
   171→    flush_rewrite_rules();
   172→}
   173→register_deactivation_hook(__FILE__, 'agentpress_deactivate');
