     2→/**
     3→ * AgentPress JSON Parser
     4→ *
     5→ * Handles JSON extraction, validation, and sanitization for API responses.
     6→ *
     7→ * @package AgentPress
     8→ * @since 1.0.0
     9→ */
    10→
    11→namespace AgentPress;
    12→
    13→/**
    14→ * Parser class for handling JSON extraction and validation.
    15→ */
    16→class Parser {
    17→
    18→    /**
    19→     * Extract JSON from a string that may contain markdown fences or extra text.
    20→     *
    21→     * Uses a layered approach:
    22→     * 1. Try direct JSON decode
    23→     * 2. Strip markdown code fences
    24→     * 3. Use recursive brace matching to find JSON object
    25→     *
    26→     * @param string $input Raw string that may contain JSON.
    27→     * @return array|string Parsed array on success, WP_Error on failure.
    28→     */
    29→    public static function extract_json($input) {
    30→        if (empty($input)) {
    31→            return new \WP_Error(
    32→                'agentpress_parser_empty',
    33→                __('Empty input provided to parser.', 'agentpress')
    34→            );
    35→        }
    36→
    37→        // Layer 1: Try direct JSON decode
    38→        $decoded = json_decode($input, true);
    39→        if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
    40→            return $decoded;
    41→        }
    42→
    43→        // Layer 2: Strip markdown code fences
    44→        $cleaned = self::strip_markdown_fences($input);
    45→        $decoded = json_decode($cleaned, true);
    46→        if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
    47→            return $decoded;
    48→        }
    49→
    50→        // Layer 3: Recursive brace matching to extract JSON object
    51→        $extracted = self::extract_json_with_brace_matching($input);
    52→        if ($extracted) {
    53→            $decoded = json_decode($extracted, true);
    54→            if (json_last_error() === JSON_ERROR_NONE && is_array($decoded)) {
    55→                return $decoded;
    56→            }
    57→        }
    58→
    59→        // All layers failed - return error
    60→        $error_message = json_last_error_msg() ?: __('Invalid JSON syntax.', 'agentpress');
    61→        return new \WP_Error(
    62→            'agentpress_parser_error',
    63→            sprintf(
    64→                /* translators: %s: JSON error message */
    65→                __('Failed to parse JSON: %s', 'agentpress'),
    66→                $error_message
    67→            )
    68→        );
    69→    }
    70→
    71→    /**
    72→     * Strip markdown code fences from input.
    73→     *
    74→     * Handles formats like:
    75→     * ```json
    76→     * {"key": "value"}
    77→     * ```
    78→     *
    79→     * @param string $input Input string.
    80→     * @return string Cleaned string without fences.
    81→     */
    82→    public static function strip_markdown_fences($input) {
    83→        // Remove opening fence with optional language specifier
    84→        $cleaned = preg_replace('/^```(?:json)?\s*\n/', '', $input);
    85→        // Remove closing fence
    86→        $cleaned = preg_replace('/\n?```$/', '', $cleaned);
    87→        // Trim whitespace
    88→        $cleaned = trim($cleaned);
    89→        return $cleaned;
    90→    }
    91→
    92→    /**
    93→     * Extract JSON object using recursive brace matching.
    94→     *
    95→     * Finds the first { and matches it with the corresponding },
    96→     * handling nested objects correctly.
    97→     *
    98→     * @param string $input Input string.
    99→     * @return string|false Extracted JSON string or false on failure.
   100→     */
   101→    public static function extract_json_with_brace_matching($input) {
   102→        $start = strpos($input, '{');
   103→        if ($start === false) {
   104→            return false;
   105→        }
   106→
   107→        $brace_count = 0;
   108→        $in_string = false;
   109→        $escape_next = false;
   110→        $length = strlen($input);
   111→
   112→        for ($i = $start; $i < $length; $i++) {
   113→            $char = $input[$i];
   114→
   115→            // Handle escape sequences
   116→            if ($escape_next) {
   117→                $escape_next = false;
   118→                continue;
   119→            }
   120→
   121→            if ($char === '\\' && $in_string) {
   122→                $escape_next = true;
   123→                continue;
   124→            }
   125→
   126→            // Track string boundaries (don't count braces inside strings)
   127→            if ($char === '"') {
   128→                $in_string = !$in_string;
   129→                continue;
   130→            }
   131→
   132→            // Count braces only outside strings
   133→            if (!$in_string) {
   134→                if ($char === '{') {
   135→                    $brace_count++;
   136→                } elseif ($char === '}') {
   137→                    $brace_count--;
   138→                    if ($brace_count === 0) {
   139→                        // Found matching closing brace
   140→                        return substr($input, $start, $i - $start + 1);
   141→                    }
   142→                }
   143→            }
   144→        }
   145→
   146→        // Unmatched braces - return what we have (may be truncated)
   147→        return substr($input, $start);
   148→    }
   149→
   150→    /**
   151→     * Validate routing JSON has required capability key.
   152→     *
   153→     * @param array $data Parsed JSON data.
   154→     * @return true|\WP_Error True on success, WP_Error on failure.
   155→     */
   156→    public static function validate_routing_json($data) {
   157→        if (!is_array($data)) {
   158→            return new \WP_Error(
   159→                'agentpress_parser_invalid_format',
   160→                __('Parsed data is not an array.', 'agentpress')
   161→            );
   162→        }
   163→
   164→        if (empty($data['capability'])) {
   165→            return new \WP_Error(
   166→                'agentpress_parser_missing_capability',
   167→                __('Missing required "capability" key in routing JSON.', 'agentpress')
   168→            );
   169→        }
   170→
   171→        // Validate capability slug format
   172→        if (!is_string($data['capability']) || !preg_match('/^[a-z_]+$/', $data['capability'])) {
   173→            return new \WP_Error(
   174→                'agentpress_parser_invalid_capability',
   175→                __('Invalid capability slug format.', 'agentpress')
   176→            );
   177→        }
   178→
   179→        return true;
   180→    }
   181→
   182→    /**
   183→     * Sanitize payload data using wp_kses_post.
   184→     *
   185→     * Recursively sanitizes all string values in the payload array.
   186→     *
   187→     * @param array|string $data Data to sanitize.
   188→     * @return array|string Sanitized data.
   189→     */
   190→    public static function sanitize_payload($data) {
   191→        if (is_array($data)) {
   192→            $sanitized = array();
   193→            foreach ($data as $key => $value) {
   194→                $sanitized[$key] = self::sanitize_payload($value);
   195→            }
   196→            return $sanitized;
   197→        } elseif (is_string($data)) {
   198→            // Strip script tags and other dangerous HTML
   199→            return wp_kses_post($data);
   200→        }
   201→        return $data;
   202→    }
   203→
   204→    /**
   205→     * Validate a capability slug against a list of known capabilities.
   206→     *
   207→     * @param string $slug Capability slug to validate.
   208→     * @param array $known_capabilities List of known capability slugs.
   209→     * @return true|\WP_Error True on success, WP_Error if slug is unknown.
   210→     */
   211→    public static function validate_capability_slug($slug, $known_capabilities) {
   212→        if (!in_array($slug, $known_capabilities, true)) {
   213→            return new \WP_Error(
   214→                'agentpress_parser_unknown_capability',
   215→                sprintf(
   216→                    /* translators: %s: capability slug */
   217→                    __('Unknown capability: %s', 'agentpress'),
   218→                    $slug
   219→                )
   220→            );
   221→        }
   222→        return true;
   223→    }
   224→}
