    11→namespace AgentPress;
    12→
    13→/**
    14→ * Logger class for activity logging with auto-prune.
    15→ */
    16→class Logger {
    17→
    18→    /**
    19→     * Maximum number of log entries to keep.
    20→     *
    21→     * @var int
    22→     */
    23→    const MAX_LOGS = 500;
    24→
    25→    /**
    26→     * Number of entries to prune when over max.
    27→     *
    28→     * @var int
    29→     */
    30→    const PRUNE_COUNT = 50;
